const manufacturerRegistry: Map<string, ManufacturerRegistryEntry> = new Map(
  PNP_REGISTRY_ENTRIES.map((entry) => [entry.id, entry])
)

export function getManufacturerInfo(pnpId: string | null | undefined): ManufacturerRegistryEntry | null {
  if (!pnpId) return null
  const normalized = pnpId.trim().toUpperCase()
  if (!normalized) return null
  return manufacturerRegistry.get(normalized) ?? null
}

export function getManufacturerName(pnpId: string | null | undefined): string | null {
  return getManufacturerInfo(pnpId)?.company ?? null
}
